mapper.select:
SELECT * FROM users
WHERE username = #{username}
  AND password = #{password}

SELECT u.*, d.name as departmentName, r.role_name as roleName FROM users u LEFT JOIN departments d ON u.department_id = d.department_id LEFT JOIN roles r ON u.role_id = r.role_id
AND u.username LIKE CONCAT('%', #{username}, '%')
AND u.department_id = #{departmentId}
